ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?salary WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:RoleID ?cg . ?child a :MedicalRoles ; p:RoleID ?cg . ?l p:HospitalID ?pg . ?parent a :Hospitals ; p:HospitalID ?pg . } GROUP BY ?child }
  ?child p:Salary ?salary .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Hospitals } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?salary WHERE {
  ?hospitals_medical_roles a :Hospitals_Medical_Roles .
  ?medicalroles a :MedicalRoles .
  ?hospitals_medical_roles p:hasMedicalRoles ?medicalroles .
  ?hospitals a :Hospitals .
  ?hospitals_medical_roles p:hasHospitals ?hospitals .
  ?hospitals p:name ?name .
  ?medicalroles p:Salary ?salary .
} }
}

